app.post('/webhooks/order', async (c) => {
  const signature = c.req.header('X-Shopify-Hmac-Sha256');
  const body = await c.req.text();
  
  // Verify webhook
  if (!verifyWebhook(body, signature, webhookSecret)) {
    return c.json({ error: 'Invalid signature' }, 401);
  }
  
  const order = JSON.parse(body);
  
  // Transform and save
  await saveShopifyOrder({
    brandId: await getBrandFromShop(order.shop_domain),
    shopifyOrderId: order.id,
    customerEmail: order.email,
    totalPrice: order.total_price,
    lineItems: order.line_items.map(item => ({
      sku: item.sku,
      quantity: item.quantity,
      price: item.price
    }))
  });
  
  return c.json({ success: true });
});`})]}),s("div",{className:"bg-gray-900 text-gray-100 rounded-lg p-6",children:[i("h3",{className:"text-lg font-semibold mb-3",children:"Courier Tracking Integration"}),i("pre",{className:"text-sm overflow-x-auto",children:`// Courier adapter pattern
